        `prompt`: kotlin.String,
        `durationSeconds`: kotlin.Float,
    ): MusicResult

    /**
     * Synchronous variant of [`generate_music`](Self::generate_music).
     */
    fun `generateMusicBlocking`(
        `prompt`: kotlin.String,
        `durationSeconds`: kotlin.Float,
    ): MusicResult

    /**
     * Generate `duration_seconds` of sound-effect audio conditioned on
     * `prompt`.
     */
