     * Synchronous variant of [`generate_sfx`](Self::generate_sfx).
     */
    fun `generateSfxBlocking`(
        `prompt`: kotlin.String,
        `durationSeconds`: kotlin.Float,
    ): MusicResult

    companion object
}

