    override suspend fun `onChunk`(`chunk`: VcChunk) =
        uniffiRustCallAsync(
            callWithHandle { uniffiHandle ->
                UniffiLib.uniffi_blazen_uniffi_fn_method_vcstreamsink_on_chunk(
                    uniffiHandle,
                    FfiConverterTypeVcChunk.lower(`chunk`),
