public object FfiConverterTypeWorkflowHandler : FfiConverter<WorkflowHandler, Long> {
    override fun lower(value: WorkflowHandler): Long = value.uniffiCloneHandle()

    override fun lift(value: Long): WorkflowHandler = WorkflowHandler(UniffiWithHandle, value)

    override fun read(buf: ByteBuffer): WorkflowHandler = lift(buf.getLong())

    override fun allocationSize(value: WorkflowHandler) = 8UL

    override fun write(
        value: WorkflowHandler,
        buf: ByteBuffer,
    ) {
        buf.putLong(lower(value))
    }
