                FfiConverterOptionalString.write(value.`detail`, buf)
                FfiConverterOptionalULong.write(value.`retryAfterMs`, buf)
                Unit
            }

            is BlazenException.Workflow -> {
                buf.putInt(10)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.Tool -> {
                buf.putInt(11)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.CallerException -> {
                buf.putInt(12)
                FfiConverterOptionalString.write(value.`name`, buf)
                FfiConverterString.write(value.`message`, buf)
                FfiConverterString.write(value.`propertiesJson`, buf)
                Unit
            }

            is BlazenException.Peer -> {
                buf.putInt(13)
                FfiConverterString.write(value.`kind`, buf)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.Persist -> {
                buf.putInt(14)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.Prompt -> {
                buf.putInt(15)
                FfiConverterString.write(value.`kind`, buf)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.Memory -> {
                buf.putInt(16)
                FfiConverterString.write(value.`kind`, buf)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.Cache -> {
                buf.putInt(17)
                FfiConverterString.write(value.`kind`, buf)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }

            is BlazenException.Cancelled -> {
                buf.putInt(18)
                Unit
            }

            is BlazenException.Internal -> {
                buf.putInt(19)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}

/**
 * Coarse categorization of what a provider does.
 *
 * Mirrors [`blazen_llm::providers::root::CapabilityKind`] but is
 * re-declared here so it can carry `#[derive(uniffi::Enum)]` for the
 * FFI surface (the upstream enum uses `serde` derives that are not
 * `uniffi::Enum`-compatible).
