sealed class TrainingEventEnum {
    data class Started(
        val `totalSteps`: kotlin.ULong,
    ) : TrainingEventEnum() {
        companion object
    }

    data class StepCompleted(
        val `step`: kotlin.ULong,
        val `loss`: kotlin.Float,
        val `learningRate`: kotlin.Double,
        val `elapsedMs`: kotlin.ULong,
