        companion object
    }

    data class EvalCompleted(
        val `step`: kotlin.ULong,
        val `evalLoss`: kotlin.Float,
    ) : TrainingEventEnum() {
        companion object
    }

    data class CheckpointSaved(
        val `step`: kotlin.ULong,
        val `path`: kotlin.String,
    ) : TrainingEventEnum() {
        companion object
    }

    data class Finished(
        val `finalLoss`: kotlin.Float,
        val `totalSteps`: kotlin.ULong,
